// Update the adjacency list of the two nodes.
// Add the smaller node to the larger node's list.
private static Map<Node,Set<Node>> update(Map<Node,Set<Node>> groupByNode, Node vertex_u, Node vertex_v){
    if (groupByNode.get(vertex_u).size() <= groupByNode.get(vertex_v).size()) {
        Set<Node> temp = groupByNode.get(vertex_u);
        groupByNode.put(vertex_u, groupByNode.get(vertex_v));
        groupByNode.put(vertex_v, temp);
    } else {
        Set<Node> temp = groupByNode.get(vertex_v);
        groupByNode.put(vertex_v, groupByNode.get(vertex_u));
        groupByNode.put(vertex_u, temp);
    }
    for (Node node : groupByNode.get(vertex_v)) {
        groupByNode.get(node).addAll(groupByNode.get(vertex_u));
    }
    return groupByNode;
}

