public static int possible_change(int[] coins, int total) {
  if (total == 0) {
    return 1;
  }
  if (total < 0) {
    return 0;
  }
  int ways = 0;
  int first = coins[0];
  int[] rest = Arrays.copyOfRange(coins, 1, coins.length);
  for (int i = 0; i <= rest.length; i++) {
    ways += possible_change(rest, total-first*i);
  }
  return ways;
}

